import { expect } from '../testing/expect';
import { describe, test } from '../testing/registry';
import {
  createProbabilityCompletedInterfaceCertificate,
  createProbabilityCoverCertificate,
  createProbabilityKernelCertificate,
  createProbabilityProcessCertificate,
  createProbabilityTraceCertificate,
  observeProbabilityRuntime,
  probabilityResidualTotal,
  PROBABILITY_CERTIFICATE_THEOREM_REFS,
  PROBABILITY_CERTIFICATE_VERSION,
} from '../probability-certificate';

describe('probability certificates', () => {
  test('creates a lossless process certificate', () => {
    const certificate = createProbabilityProcessCertificate({
      certificateId: 'process/lossless',
      target: 'agent.step',
      inputMass: 12,
      outputMass: 12,
      massLoss: 0,
    });

    expect(certificate.version).toBe(PROBABILITY_CERTIFICATE_VERSION);
    expect(certificate.balanceHolds).toBe(true);
    expect(certificate.lossCovered).toBe(true);
    expect(certificate.residualTotal).toBe(0);
    expect(certificate.badge).toBe('lossless');
    expect(certificate.theoremRefs).toContain(
      'Gnosis.FiniteProbabilityCore.RuntimeProbabilityProcessCertificate',
    );
  });

  test('keeps mass loss visible through residual coverage', () => {
    const certificate = createProbabilityProcessCertificate({
      certificateId: 'process/truncated',
      target: 'summary.window',
      inputMass: 100,
      outputMass: 76,
      massLoss: 24,
      residual: {
        truncatedMass: 18,
        coarseningDebt: 6,
      },
      residualBudget: 30,
    });

    expect(certificate.balanceHolds).toBe(true);
    expect(certificate.lossCovered).toBe(true);
    expect(certificate.residualTotal).toBe(24);
    expect(certificate.badge).toBe('bounded-residual');
  });

  test('marks uncovered loss as needing cover', () => {
    const certificate = createProbabilityProcessCertificate({
      certificateId: 'process/uncovered',
      target: 'router.branch',
      inputMass: 30,
      outputMass: 20,
      massLoss: 10,
      residual: {
        unobservedMass: 4,
      },
    });

    expect(certificate.balanceHolds).toBe(true);
    expect(certificate.lossCovered).toBe(false);
    expect(certificate.badge).toBe('needs-cover');
  });

  test('validates kernel and cover arithmetic', () => {
    const kernel = createProbabilityKernelCertificate({
      certificateId: 'kernel/k',
      target: 'classifier.kernel',
      inputMass: 55,
      outputMass: 50,
      lostMass: 5,
    });
    const cover = createProbabilityCoverCertificate({
      certificateId: 'cover/c',
      target: 'conversation.window',
      footprint: 32,
      shadow: 7,
      horizonDepth: 40,
      horizonResidualBudget: 10,
    });

    expect(kernel.balanceHolds).toBe(true);
    expect(kernel.outputMassWithinInput).toBe(true);
    expect(cover.footprintBounded).toBe(true);
    expect(cover.shadowBounded).toBe(true);
    expect(cover.badge).toBe('bounded-residual');
  });

  test('mirrors completed interfaces as bounded finite covers', () => {
    const certificate = createProbabilityCompletedInterfaceCertificate({
      certificateId: 'completed/interface',
      target: 'long-context.cover',
      visibleDepth: 128,
      shadow: 12,
      horizonDepth: 160,
      horizonResidualBudget: 16,
    });

    expect(certificate.depthWithinHorizon).toBe(true);
    expect(certificate.shadowWithinHorizon).toBe(true);
    expect(certificate.badge).toBe('bounded-residual');
  });

  test('folds process certificates into trace accounting', () => {
    const first = createProbabilityProcessCertificate({
      certificateId: 'step/1',
      target: 'trace.step.1',
      inputMass: 100,
      outputMass: 90,
      massLoss: 10,
      residual: { unobservedMass: 10 },
    });
    const second = createProbabilityProcessCertificate({
      certificateId: 'step/2',
      target: 'trace.step.2',
      inputMass: 90,
      outputMass: 75,
      massLoss: 15,
      residual: { truncatedMass: 15 },
    });

    const trace = createProbabilityTraceCertificate({
      certificateId: 'trace/t',
      target: 'agent.trace',
      steps: [first, second],
      residualBudget: 30,
    });

    expect(trace.inputMass).toBe(100);
    expect(trace.outputMass).toBe(75);
    expect(trace.massLoss).toBe(25);
    expect(trace.residualTotal).toBe(25);
    expect(trace.balanceHolds).toBe(true);
    expect(trace.lossCovered).toBe(true);
    expect(trace.badge).toBe('bounded-residual');
  });

  test('folds additive process certificates for runtime evidence traces', () => {
    const spine = createProbabilityProcessCertificate({
      certificateId: 'runtime/spine',
      target: 'engine.spine',
      inputMass: 3,
      outputMass: 2,
      massLoss: 1,
      residual: { unobservedMass: 1 },
    });
    const branch = createProbabilityProcessCertificate({
      certificateId: 'runtime/branch',
      target: 'engine.branch',
      inputMass: 4,
      outputMass: 1,
      massLoss: 3,
      residual: { coarseningDebt: 3 },
    });

    const trace = createProbabilityTraceCertificate({
      certificateId: 'trace/runtime',
      target: 'engine.run',
      mode: 'additive',
      steps: [spine, branch],
      residualBudget: 4,
    });

    expect(trace.inputMass).toBe(7);
    expect(trace.outputMass).toBe(3);
    expect(trace.massLoss).toBe(4);
    expect(trace.residualTotal).toBe(4);
    expect(trace.balanceHolds).toBe(true);
    expect(trace.badge).toBe('bounded-residual');
  });

  test('residual total is exact natural-number addition', () => {
    expect(
      probabilityResidualTotal({
        unobservedMass: 3,
        truncatedMass: 5,
        coarseningDebt: 8,
      }),
    ).toBe(16);
    expect(PROBABILITY_CERTIFICATE_THEOREM_REFS.length).toBeGreaterThan(4);
  });

  test('observes lossless certificates as runtime continue decisions', () => {
    const certificate = createProbabilityProcessCertificate({
      certificateId: 'observe/lossless',
      target: 'runtime.step',
      inputMass: 8,
      outputMass: 8,
      massLoss: 0,
    });

    expect(observeProbabilityRuntime(certificate).decision).toBe('continue');
  });

  test('observes uncovered certificates as cover decisions', () => {
    const certificate = createProbabilityProcessCertificate({
      certificateId: 'observe/cover',
      target: 'runtime.step',
      inputMass: 8,
      outputMass: 6,
      massLoss: 2,
      residual: { truncatedMass: 1 },
    });

    const decision = observeProbabilityRuntime(certificate);

    expect(decision.decision).toBe('cover');
    expect(decision.residualTotal).toBe(1);
  });

  test('observes bounded trace residual as shrink-horizon decisions', () => {
    const certificate = createProbabilityTraceCertificate({
      certificateId: 'observe/trace',
      target: 'runtime.trace',
      mode: 'additive',
      steps: [
        createProbabilityProcessCertificate({
          certificateId: 'observe/trace/step',
          target: 'runtime.trace.step',
          inputMass: 10,
          outputMass: 8,
          massLoss: 2,
          residual: { coarseningDebt: 2 },
        }),
      ],
      residualBudget: 2,
    });

    expect(observeProbabilityRuntime(certificate).decision).toBe(
      'shrink-horizon',
    );
  });

  test('observes excessive residual as human escalation decisions', () => {
    const certificate = createProbabilityTraceCertificate({
      certificateId: 'observe/escalate',
      target: 'runtime.trace',
      mode: 'additive',
      steps: [
        createProbabilityProcessCertificate({
          certificateId: 'observe/escalate/step',
          target: 'runtime.trace.step',
          inputMass: 20,
          outputMass: 12,
          massLoss: 8,
          residual: { unobservedMass: 8 },
        }),
      ],
      residualBudget: 8,
    });

    expect(
      observeProbabilityRuntime(certificate, { escalationBudget: 3 }).decision,
    ).toBe('human-escalation');
  });
});
